import{c as t,Q as r,j as a,m as o}from"./chunks/framework.DVkeSyfh.js";const p=JSON.parse('{"title":"Smart Set Builder","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/smart-set-builder.md","filePath":"user-guide/smart-set-builder.md","lastUpdated":null}'),s={name:"user-guide/smart-set-builder.md"};function i(d,e,l,n,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="smart-set-builder" tabindex="-1">Smart Set Builder <a class="header-anchor" href="#smart-set-builder" aria-label="Permalink to &quot;Smart Set Builder&quot;">​</a></h1><p>Audience: DJs and advanced UI users<br> Goal: generate ordered read-only set previews<br> Type: how-to</p><p>Smart Set Builder, shown as the <code>SET</code> tab, builds an ordered preview from manual seeds or automatic anchors. It does not modify the library. You add the preview to the current set only with an explicit action.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>SET needs feature-complete candidates:</p><ul><li>SONARA features;</li><li>MERT embeddings;</li><li>MAEST embeddings;</li><li>CLAP audio embeddings.</li></ul><p>MAEST genre labels are not the selection source for SET. MAEST embeddings can be used as one similarity signal.</p><h2 id="seed-source" tabindex="-1">Seed source <a class="header-anchor" href="#seed-source" aria-label="Permalink to &quot;Seed source&quot;">​</a></h2><ul><li><code>Manual</code>: use the tracks you selected as seeds.</li><li><code>Auto</code>: choose the first anchor from the feature-complete library, then build related waypoint anchors and bridge tracks.</li></ul><p>Manual seeds with the same known artist are rejected. Generated previews also keep a strict known-artist guard.</p><h2 id="core-controls" tabindex="-1">Core controls <a class="header-anchor" href="#core-controls" aria-label="Permalink to &quot;Core controls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Meaning</th></tr></thead><tbody><tr><td><code>Set mode</code></td><td>Similar crate, weird adjacent, balanced set, or discovery.</td></tr><tr><td><code>Track limit</code></td><td>Number of preview tracks, from 1 to 500.</td></tr><tr><td><code>Auto anchors</code></td><td>Number of automatic anchors, from 1 to 5.</td></tr><tr><td><code>Energy curve</code></td><td>Warmup, balanced, peak, or wave intensity shape.</td></tr><tr><td><code>Diversity</code></td><td>How broadly the route explores related candidates.</td></tr></tbody></table><h2 id="bpm-controls" tabindex="-1">BPM controls <a class="header-anchor" href="#bpm-controls" aria-label="Permalink to &quot;BPM controls&quot;">​</a></h2><p><code>BPM mode = general</code> keeps normal transition compatibility. <code>low_to_high</code> or <code>high_to_low</code> adds an actual BPM trajectory.</p><p>When file tag BPM exists, SET prefers that value. SONARA BPM is a fallback. Half/double tempo matching helps transition compatibility; it does not rewrite the actual BPM trajectory.</p><h2 id="classifier-controls" tabindex="-1">Classifier controls <a class="header-anchor" href="#classifier-controls" aria-label="Permalink to &quot;Classifier controls&quot;">​</a></h2><p>Promoted classifier scores are optional modifiers. Missing scores stay neutral. Preference can be positive or negative, and flow can be flat, rise, or fall.</p><p>Use <code>Reset sliders</code> to reset diversity plus classifier preference/flow values without changing seed source, mode, limit, anchors, energy curve, or BPM controls.</p><h2 id="add-the-preview" tabindex="-1">Add the preview <a class="header-anchor" href="#add-the-preview" aria-label="Permalink to &quot;Add the preview&quot;">​</a></h2><p>Generate the preview, listen, inspect the list, then use the add action to move the preview into the current set. Export remains a separate step.</p>',20)])])}const m=t(s,[["render",i]]);export{p as __pageData,m as default};
